var contentRoot = builder.Environment.ContentRootPath;
var dataPath = Path.Combine(contentRoot, "Data", "tickets.csv");
var modelPath = Path.Combine(contentRoot, "Data", "model.zip");

TrainModel(dataPath, modelPath);

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

static void TrainModel(string dataPath, string modelPath)
{
    var mlContext = new Microsoft.ML.MLContext(seed: 42);

    var data = mlContext.Data.LoadFromTextFile<TicketInput>(
        dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

    var pipeline = mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketInput.Category))
        .Append(mlContext.Transforms.Text.FeaturizeText(
            "SubjectFeaturized", nameof(TicketInput.Subject)))
        .Append(mlContext.Transforms.Text.FeaturizeText(
            "DescriptionFeaturized", nameof(TicketInput.Description)))
        .Append(mlContext.Transforms.Concatenate("Features",
            "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
        .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
        .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

    var model = pipeline.Fit(data);
    mlContext.Model.Save(model, data.Schema, modelPath);
}

